(window.webpackJsonp=window.webpackJsonp||[]).push([[825],{814:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> getStrongest = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr, k</span>) </span>{\\n  arr.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>a-b)\\n  <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n  <span class=\\"hljs-keyword\\">let</span> m=arr[<span class=\\"hljs-built_in\\">Math</span>.floor((len<span class=\\"hljs-number\\">-1</span>)/<span class=\\"hljs-number\\">2</span>)]\\n  arr.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>{\\n    <span class=\\"hljs-keyword\\">let</span> absA=<span class=\\"hljs-built_in\\">Math</span>.abs(a-m)\\n    <span class=\\"hljs-keyword\\">let</span> absB=<span class=\\"hljs-built_in\\">Math</span>.abs(b-m)\\n    <span class=\\"hljs-keyword\\">if</span>(absA===absB){\\n      <span class=\\"hljs-keyword\\">return</span> a &lt; b ? <span class=\\"hljs-number\\">1</span> : <span class=\\"hljs-number\\">-1</span>\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      <span class=\\"hljs-keyword\\">return</span> absA &lt; absB ? <span class=\\"hljs-number\\">1</span> : <span class=\\"hljs-number\\">-1</span>\\n    }\\n  })\\n  <span class=\\"hljs-keyword\\">return</span> arr.slice(<span class=\\"hljs-number\\">0</span>,k)\\n};\\n</code></pre>\\n"],"titleSlug":"the-k-strongest-values-in-an-array","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>arr</code> \u548c\u4e00\u4e2a\u6574\u6570 <code>k</code> \u3002</p>\\n\\n<p>\u8bbe <code>m</code> \u4e3a\u6570\u7ec4\u7684\u4e2d\u4f4d\u6570\uff0c\u53ea\u8981\u6ee1\u8db3\u4e0b\u8ff0\u4e24\u4e2a\u524d\u63d0\u4e4b\u4e00\uff0c\u5c31\u53ef\u4ee5\u5224\u5b9a <code>arr[i]</code> \u7684\u503c\u6bd4 <code>arr[j]</code> \u7684\u503c\u66f4\u5f3a\uff1a</p>\\n\\n<ul>\\n\\t<li>&nbsp;<code>|arr[i] - m| &gt; |arr[j]&nbsp;- m|</code></li>\\n\\t<li>&nbsp;<code>|arr[i] - m| == |arr[j] - m|</code>\uff0c\u4e14 <code>arr[i] &gt; arr[j]</code></li>\\n</ul>\\n\\n<p>\u8bf7\u8fd4\u56de\u7531\u6570\u7ec4\u4e2d\u6700\u5f3a\u7684 <code>k</code> \u4e2a\u503c\u7ec4\u6210\u7684\u5217\u8868\u3002\u7b54\u6848\u53ef\u4ee5\u4ee5 <strong>\u4efb\u610f\u987a\u5e8f</strong> \u8fd4\u56de\u3002</p>\\n\\n<p><strong>\u4e2d\u4f4d\u6570</strong> \u662f\u4e00\u4e2a\u6709\u5e8f\u6574\u6570\u5217\u8868\u4e2d\u5904\u4e8e\u4e2d\u95f4\u4f4d\u7f6e\u7684\u503c\u3002\u5f62\u5f0f\u4e0a\uff0c\u5982\u679c\u5217\u8868\u7684\u957f\u5ea6\u4e3a <code>n</code> \uff0c\u90a3\u4e48\u4e2d\u4f4d\u6570\u5c31\u662f\u8be5\u6709\u5e8f\u5217\u8868\uff08\u4e0b\u6807\u4ece 0 \u5f00\u59cb\uff09\u4e2d\u4f4d\u4e8e <code>((n - 1) / 2)</code> \u7684\u5143\u7d20\u3002</p>\\n\\n<ul>\\n\\t<li>\u4f8b\u5982 <code>arr =&nbsp;[6, -3, 7, 2, 11]</code>\uff0c<code>n = 5</code>\uff1a\u6570\u7ec4\u6392\u5e8f\u540e\u5f97\u5230 <code>arr = [-3, 2, 6, 7, 11]</code> \uff0c\u6570\u7ec4\u7684\u4e2d\u95f4\u4f4d\u7f6e\u4e3a <code>m = ((5 - 1) / 2) = 2</code> \uff0c\u4e2d\u4f4d\u6570 <code>arr[m]</code> \u7684\u503c\u4e3a <code>6</code> \u3002</li>\\n\\t<li>\u4f8b\u5982 <code>arr =&nbsp;[-7, 22, 17,&thinsp;3]</code>\uff0c<code>n = 4</code>\uff1a\u6570\u7ec4\u6392\u5e8f\u540e\u5f97\u5230&nbsp;<code>arr = [-7, 3, 17, 22]</code> \uff0c\u6570\u7ec4\u7684\u4e2d\u95f4\u4f4d\u7f6e\u4e3a&nbsp;<code>m = ((4 - 1) / 2) = 1</code> \uff0c\u4e2d\u4f4d\u6570 <code>arr[m]</code> \u7684\u503c\u4e3a <code>3</code> \u3002</li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,2,3,4,5], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>[5,1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e2d\u4f4d\u6570\u4e3a 3\uff0c\u6309\u4ece\u5f3a\u5230\u5f31\u987a\u5e8f\u6392\u5e8f\u540e\uff0c\u6570\u7ec4\u53d8\u4e3a [5,1,4,2,3]\u3002\u6700\u5f3a\u7684\u4e24\u4e2a\u5143\u7d20\u662f [5, 1]\u3002[1, 5] \u4e5f\u662f\u6b63\u786e\u7b54\u6848\u3002\\n\u6ce8\u610f\uff0c\u5c3d\u7ba1 |5 - 3| == |1 - 3| \uff0c\u4f46\u662f 5 \u6bd4 1 \u66f4\u5f3a\uff0c\u56e0\u4e3a 5 &gt; 1 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,1,3,5,5], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>[5,5]\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e2d\u4f4d\u6570\u4e3a 3, \u6309\u4ece\u5f3a\u5230\u5f31\u987a\u5e8f\u6392\u5e8f\u540e\uff0c\u6570\u7ec4\u53d8\u4e3a [5,5,1,1,3]\u3002\u6700\u5f3a\u7684\u4e24\u4e2a\u5143\u7d20\u662f [5, 5]\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [6,7,11,7,6,8], k = 5\\n<strong>\u8f93\u51fa\uff1a</strong>[11,8,6,6,7]\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e2d\u4f4d\u6570\u4e3a 7, \u6309\u4ece\u5f3a\u5230\u5f31\u987a\u5e8f\u6392\u5e8f\u540e\uff0c\u6570\u7ec4\u53d8\u4e3a [11,8,6,6,7,7]\u3002\\n[11,8,6,6,7] \u7684\u4efb\u4f55\u6392\u5217\u90fd\u662f\u6b63\u786e\u7b54\u6848\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [6,-3,7,2,11], k = 3\\n<strong>\u8f93\u51fa\uff1a</strong>[-3,11,2]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [-7,22,17,3], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>[22,17]\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= arr.length &lt;= 10^5</code></li>\\n\\t<li><code>-10^5 &lt;= arr[i] &lt;= 10^5</code></li>\\n\\t<li><code>1 &lt;= k &lt;= arr.length</code></li>\\n</ul>\\n","title":"1471. \u6570\u7ec4\u4e2d\u7684 k \u4e2a\u6700\u5f3a\u503c","relatedTags":["\u6392\u5e8f","\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1471"}')}}]);